var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"이곳이 의뢰인의 저택…. 소문대로 엄청나네요.","JPN":"こちらが依頼人の邸宅……噂どおり、すごいですね。","ENG":"So this is the client's mansion... It's massive, just like the rumors said it was.","TWN":"這裡就是委託人的豪宅…正如傳聞，果然奢華。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"우와… 우리 사무소와는 비교도 안 되잖아…?","JPN":"うわ……僕たちの事務所とは比べ物にならないな……","ENG":"Wow... Our office is tiny compared to here...!","TWN":"哇…我們事務所根本沒法比啊…？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"당연하지. 아가씨는 이 동네 최고 부자거든!","JPN":"当然でしょ？　お嬢様はこの街で随一のお金持ちなんだから！","ENG":"Of course it is. Our lady is the richest in town!","TWN":"當然。小姐是這個地方最富有的人！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"내가 먹을 간식도 매일 따로 준비해 주신다구~","JPN":"アタシのおやつも毎日用意してくれるし。","ENG":"She even prepares my own snacks every day!","TWN":"甚至每天都會另外為我準備零食～"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"FOOLSDAY_DRAKO_MAID_NULL","text":{"KOREA":"그건 네가 하도 훔쳐먹으니까 그렇지.","JPN":"それはお前が盗み食いするからだろ？","ENG":"That's because you keep stealing hers.","TWN":"還不是因為你一直在偷吃。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"FOOLSDAY_DRAKO_MAID_NULL","text":{"KOREA":"너 또 아가씨께 드릴 간식을 다 먹냐!","JPN":"お前、またお嬢様のおやつを横取りしたな！","ENG":"And just as I'm talking, you ate our lady's snacks again?!","TWN":"你又把要給小姐的零食都吃光了啊！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"아얏! 먹는데 때리는 게 어딨어!","JPN":"イタっ！　食べてる時に殴るのはナシだよ～！","ENG":"Oww! Don't hit me when I'm eating!","TWN":"哎呀！吃東西的時候怎麼能打人？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_03"},{"id":"L13_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"다들 모였군. 만나서 반갑다 탐정!","JPN":"みんな集まったようだな。会えて嬉しいぞ、探偵！","ENG":"You're all here. Nice to see you, Detective!","TWN":"看來都來了啊。很高興認識你們，兩位偵探！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"어이 카일. 설마 저들이 날 모르진 않겠지?","JPN":"おい、カイル。この者たちに私を紹介する必要なあるか？","ENG":"Hey, Kyle. Don't tell me that they don’t know who I am.","TWN":"喂，凱爾。他們不會不認識我吧？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"설마 아가씨를 모를 정도로 무식한 사람들은 아닐 겁니다.","JPN":"まさか、お嬢様を知らないような無知な者ではないはずです。","ENG":"I don't believe anyone is ignorant enough to not know who you are, Miss Lin.","TWN":"我想她們不會無知到不認識小姐您。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"저분들도… 나름 탐정이니까요.","JPN":"この人たちも……一応は探偵ですから。","ENG":"They are... detectives still.","TWN":"畢竟那些人…也算是偵探。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어…? 카린과 똑 닮은 사람이잖아?!","JPN":"あれ……？　カリンとそっくりじゃないか！？","ENG":"Huh...? He looks just like Karin!","TWN":"呃…？和卡琳長得一模一樣？！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"우연이라기엔 성격이나 말투까지 비슷한데? 설마 숨겨둔 남동생이 있었던 거야?","JPN":"偶然にしては、性格や言葉使いも似ているぞ？　もしかして、隠してた弟がいたのか？","ENG":"Their personalities and way of speaking are so similar that it cannot be a coincidence. Hey, have you hidden your brother all these years?","TWN":"要說是巧合，性格和說話方式也太相似了吧？難道卡琳你還有個弟弟嗎？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"뭐, 뭐라고요?!","JPN":"な、何ですって！？","ENG":"W-what?!","TWN":"什、什麼？！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"실례되는 말을 아무렇지도 않게 하시는군요.","JPN":"失礼なことを平気で言うのですね。","ENG":"How brazen of you to make such rude remarks.","TWN":"竟然如此無禮。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_BOTH","text":{"KOREA":"도대체 제가 어딜 봐서 저 사람이랑 닮았다는 겁니까!","JPN":"いったいどこがこの人と似ていると言うのですか！","ENG":"In what world do I look like him?!","TWN":"我們才不像呢！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L26_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"안 되겠습니다 아가씨. 저 사람들을 도저히 신용할 수 없군요.","JPN":"いけません、お嬢様。この人たちは信用できません。","ENG":"This will not do, Miss Lin. I do not trust those people one bit.","TWN":"不行，小姐。我實在無法相信那兩人。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"지금이라도 그냥 경찰을 부르는 게 어떻습니까?","JPN":"今からでも警察を呼びしましょうか？","ENG":"Shall I take the liberty to call the cops?","TWN":"要不還是直接報警吧？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"쓸데없는 소리는 금지하겠습니다.","JPN":"無駄口は禁止にします。","ENG":"I'll stop speaking nonsense.","TWN":"別說廢話了。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"이쪽은 시급한 임무를 수행하는 중이니 어서 차나 대접해 주시죠.","JPN":"こちらは急ぎの任務を遂行している最中です。さっさとお茶でも出してください。","ENG":"We are busy with urgent matters, so how about you serve us some tea?","TWN":"我們正在執行一項緊急任務，所以請快點給我們倒杯茶吧。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"상대방에게 실례되는 언행과 더불어 손님 접대도 0점이네요. 집사 실격입니다.","JPN":"失礼な態度に、おもてなしも0点ですね。執事失格です。","ENG":"In addition to being rude to your guests, you're poor at hospitality. You give butlers a bad name.","TWN":"不僅無禮，連接待客人也是0分。你這樣的人，不配當管家。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"괴도에게 놀아난 당신이야말로 탐정 실격이겠죠.","JPN":"怪盗に弄ばれたあなたこそ、探偵失格でしょう。","ENG":"And you give detectives a bad name by failing to catch the phantom thief.","TWN":"被怪盜玩弄於股掌之中的你才不配當偵探吧。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"어, 어떻게 그걸…?!","JPN":"ど、どうしてそれを……！？","ENG":"H-how did you know about that...?!","TWN":"你、你怎麼知道…？！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"둘 다 그만 좀 해. 여기 싸우러 온 것도 아니잖아.","JPN":"二人とも、やめろよ。ケンカしに来たんじゃないだろ。","ENG":"Both of you, enough. We are not here to fight.","TWN":"你們兩個都別說了。我們不是來這裡吵架的…"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"역시 남매가 아니고서야….","JPN":"それとも、やっぱり姉弟なんじゃ……","ENG":"Plus, only siblings would fight like that...","TWN":"除非是兄妹或者姊弟，不然怎麼可能…"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_BOTH","text":{"KOREA":"시끄럽습니다!","JPN":"うるさいです！","ENG":"Hold your tongue!","TWN":"閉嘴！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L44_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"…"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"탐정의 실력은 확실하니까 걱정할 것 없어.","JPN":"探偵としての実力は確かだ。心配ない。","ENG":"I don't question your skills as detectives, so don't worry.","TWN":"放心，偵探的實力沒問題的。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"천재적인 추리력으로 지금까지 수많은 범죄자를 붙잡았다는 명성이 자자하다고.","JPN":"天才的な推理力で、今まで数多くの犯罪者を捕まえたって話じゃないか。","ENG":"I've heard enough of your genius criminal-catching detective skills to know.","TWN":"她憑藉著天才般的推理能力捕獲眾多罪犯，也因此而遠近聞名。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"범죄자를 몰아넣은 뒤, 특수 화기가 장착된 가방으로 화력 전개를 펼친다는…!","JPN":"犯罪者を追い詰め、特殊火器付きのカバンで火力展開を繰り広げるという……！","ENG":"You put them in a corner, then deploy your suitcase equipped with a special firearm to blast them into bits...!","TWN":"將罪犯逼入絕境後，使用裝有特殊槍械的手提箱火力全開…！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그건 탐정과는 전혀 상관 없지 않습니까….","JPN":"それは、探偵とは関係がないのでは……？","ENG":"But that has absolutely nothing to do with being a detective, Miss Lin...","TWN":"這和偵探完全沒有關係…"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"훗, 집사분과는 다르게 정확한 안목이시네요 아가씨.","JPN":"ふっ、執事の方とは違って、お目が高いですね。お嬢様。","ENG":"Heh, looks like you got a keen eye for people, unlike your butler, Miss Lin.","TWN":"呵，與管家不同，你的目光很準確，大小姐。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"탐정이란 사무실에 앉아 추리만 하는 사람이 아닙니다.","JPN":"探偵とは、事務室に座って推理ばかりをしているわけではありません。","ENG":"A detective isn't someone who only sits in their office trying to connect clues together.","TWN":"身為偵探，不能只坐在辦公室裡推理。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"악랄한 범죄자들을 상대하기 위해선, 그에 따른 무력을 갖출 필요가 있어요.","JPN":"醜悪な犯罪者を相手するためには、それ相応の武力を備える必要があるのです。","ENG":"In order to deal with vicious criminals, they have to use some force sometimes.","TWN":"想對付惡毒的犯罪分子，就必須具備相應的武力。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"하하! 벌써부터 가슴이 웅장해지는구만!","JPN":"フッフッフ！　もう胸が高鳴るな！","ENG":"Hah hah! I can already feel my heart racing!","TWN":"哈哈哈！我現在就已經很激動了！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이런 건 돈으로도 얻을 수 없는 귀중한 경험 아니겠어?","JPN":"このようなことは、お金では手に入れられない貴重な経験だろう？","ENG":"This is a valuable experience that money can't buy, no?","TWN":"這是一段用金錢也無法買到的寶貴經歷呀？！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"아가씨… 조금은 진지하게 임해주시죠.","JPN":"お嬢様……もう少し真面目に取り組んでください。","ENG":"Miss Lin... will you please take this seriously?","TWN":"小姐…請您認真一點。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"아 그렇지, 이게 그 예고장이야.","JPN":"ああ、そうそう。これが例の予告状だ。","ENG":"Oh, right. This is the calling card I got.","TWN":"喔，對了，這是預告函。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"FOOLSDAY_THIEF_LETTER_NULL","text":{"KOREA":"<color=#ffd34c>보름달이 아름답게 뜨는 날. 당신의 가장 소중한 그림을 훔쳐줄게.</color>","JPN":"<color=#ffd34c>満月が綺麗な日。あなたの一番大切な絵を盗んでみせよう。</color>","ENG":"<color=#ffd34c>When the full moon shines bright. Your most cherished painting will become mine.</color>","TWN":"<color=#ffd34c>美麗的滿月升起的那一天，我會偷走你最珍貴的畫。</color>"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L16_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"이게 아마 녀석이 노리는 그림일 거야.","JPN":"恐らく、やつの狙いはこの絵だ。","ENG":"It appears that the thief is after a painting.","TWN":"這大概就是那傢伙的計畫了。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"녀석은 CCTV에도 잡히지 않았고, 주변엔 목격자조차 없었어.","JPN":"やつは監視カメラにも姿を映さず、周りには目撃者すらいなかった。","ENG":"But our security cameras couldn't catch the thief, nor were there any witnesses.","TWN":"那傢伙既沒有被監控錄影拍到，周圍也沒有任何目擊者…"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗, 괴도와 미술품은 뗄래야 뗄 수 없는 관계 아니겠어?","JPN":"ふっ、怪盗と美術品とは、切っても切れない関係だろう？","ENG":"Heh, phantom thieves always have a thing for artworks, don't they?","TWN":"呵，難道怪盜和藝術也是密不可分的關係嗎？"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"일단 그림을 안전한 장소로 옮겨야겠어요.","JPN":"とりあえず、絵を安全な場所に移す必要がありますね。","ENG":"Then, let's first move the painting to a secure location.","TWN":"首先，把畫轉移到安全的地方吧。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"지하 창고가 좋겠네요. 그곳이라면 도주 경로도 쉽게 확보할 수 없을 테니까요.","JPN":"地下倉庫が良いでしょう。あそこならそう簡単に逃走経路を確保できません。","ENG":"The basement storage room should do. Because there won't be many escape routes down there.","TWN":"最好是搬到地下倉庫，那個地方很難逃出去。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"경비는 저와 로널드 씨가 함께 교대하며 서겠습니다.","JPN":"警備は私とロナルド・リー。二人で交代しながらやります。","ENG":"Ronald Lee and I will stand guard in shifts.","TWN":"由我和羅那魯多·李兩個人輪流看守。"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"상대는 괴도 J. 어떤 트릭을 사용할지 모르니 철저히 대비하죠!","JPN":"相手は怪盗J。どんなトリックを使うかわからないので、徹底的に準備しましょう！","ENG":"We're dealing with the Phantom Thief J. Better be prepared as we don't know what tricks she'll use!","TWN":"對手是怪盜J，你永遠不知道她會使用什麼招數，所以要做好充分準備！"},"stage":{"bg":"ROOM_04","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};